css:
.wrapper-crm-tickets-time {
  --ctt-surface: var(--block-bg-color, #15151A);
  --ctt-surface-raised: #1B1B22;
  --ctt-ink: var(--color-text, #F4F4F7);
  --ctt-muted: var(--color-gray-500, #8A8A96);
  --ctt-line: var(--color-gray-200, rgba(255,255,255,0.07));
  --ctt-accent: var(--color-primary, #FFD21E);
  --ctt-accent-2: var(--color-secondary, #FF3D8B);
  --ctt-font: var(--font-stack-primary, 'Inter', system-ui, -apple-system, 'Segoe UI', Roboto, sans-serif);
  container-type: inline-size;
  box-sizing: border-box;
  width: 100%;
  max-width: 100%;
  height: 100%;
  color: var(--ctt-ink);
  font-family: var(--ctt-font);
  font-variant-numeric: tabular-nums;
}
.wrapper-crm-tickets-time .card-ctt {
  box-sizing: border-box;
  display: flex;
  flex-direction: column;
  width: 100%;
  max-width: 100%;
  height: 100%;
  min-height: 340px;
  min-width: 0;
  overflow: hidden;
  background: var(--ctt-surface);
  border: 1px solid var(--ctt-line);
  border-radius: 14px;
  padding: 16px 18px;
  box-shadow: 0 1px 0 rgba(255,255,255,0.03) inset, 0 6px 18px rgba(0,0,0,0.5);
  transition: border-color .16s ease, box-shadow .16s ease, background-color .16s ease;
}
.wrapper-crm-tickets-time .card-ctt:hover {
  border-color: color-mix(in srgb, var(--ctt-accent) 35%, var(--ctt-line));
  box-shadow: 0 1px 0 rgba(255,255,255,0.04) inset, 0 10px 26px rgba(0,0,0,0.55);
}
.wrapper-crm-tickets-time .card-ctt.is-active {
  background: var(--ctt-surface-raised);
  border-color: color-mix(in srgb, var(--ctt-accent) 55%, var(--ctt-line));
  box-shadow: 0 1px 0 rgba(255,255,255,0.04) inset, 0 8px 24px rgba(0,0,0,0.55), 0 0 26px -10px color-mix(in srgb, var(--ctt-accent) 60%, transparent);
}
.wrapper-crm-tickets-time :focus-visible {
  outline: 2px solid var(--ctt-accent);
  outline-offset: 2px;
  border-radius: 8px;
}
.wrapper-crm-tickets-time .head-ctt {
  box-sizing: border-box;
  display: flex;
  flex-direction: column;
  gap: 3px;
  margin-bottom: 14px;
  min-width: 0;
}
.wrapper-crm-tickets-time .eyebrow-ctt {
  display: inline-flex;
  align-items: center;
  font: 700 11px/1.2 var(--ctt-font);
  letter-spacing: .13em;
  text-transform: uppercase;
  color: var(--ctt-muted);
}
.wrapper-crm-tickets-time .eyebrow-ctt::before {
  content: "";
  flex: none;
  width: 7px;
  height: 7px;
  border-radius: 50%;
  margin-right: 8px;
  background: var(--ctt-accent);
}
.wrapper-crm-tickets-time .title-ctt {
  margin: 0;
  font: 800 14px/1.3 var(--ctt-font);
  letter-spacing: -0.01em;
  color: var(--ctt-ink);
  overflow-wrap: anywhere;
  word-break: break-word;
}
.wrapper-crm-tickets-time .sub-ctt {
  font: 500 11px/1.35 var(--ctt-font);
  color: var(--ctt-muted);
  overflow-wrap: anywhere;
  word-break: break-word;
}
.wrapper-crm-tickets-time .body-ctt {
  position: relative;
  box-sizing: border-box;
  flex: 1 1 auto;
  display: flex;
  flex-direction: column;
  min-height: 280px;
  min-width: 0;
}
.wrapper-crm-tickets-time .canvas-ctt {
  box-sizing: border-box;
  flex: 1 1 auto;
  width: 100%;
  max-width: 100%;
  min-width: 0;
  min-height: 280px;
}
.wrapper-crm-tickets-time .empty-ctt {
  margin: auto;
  max-width: 100%;
  font: 600 12px/1.4 var(--ctt-font);
  color: var(--ctt-muted);
  text-align: center;
  overflow-wrap: anywhere;
}
@container (max-width: 720px) {
  .wrapper-crm-tickets-time .card-ctt { min-height: 320px; padding: 16px; }
  .wrapper-crm-tickets-time .head-ctt { margin-bottom: 12px; }
  .wrapper-crm-tickets-time .canvas-ctt { min-height: 240px; }
  .wrapper-crm-tickets-time .body-ctt { min-height: 240px; }
}
@container (max-width: 480px) {
  .wrapper-crm-tickets-time .card-ctt { min-height: 300px; padding: 14px; }
  .wrapper-crm-tickets-time .head-ctt { margin-bottom: 10px; }
  .wrapper-crm-tickets-time .title-ctt { font-size: 13.5px; }
  .wrapper-crm-tickets-time .sub-ctt { font-size: 10.5px; }
  .wrapper-crm-tickets-time .canvas-ctt { min-height: 220px; }
  .wrapper-crm-tickets-time .body-ctt { min-height: 220px; }
}
@supports not (container-type: inline-size) {
  @media (max-width: 720px) {
    .wrapper-crm-tickets-time .card-ctt { min-height: 320px; padding: 16px; }
    .wrapper-crm-tickets-time .head-ctt { margin-bottom: 12px; }
    .wrapper-crm-tickets-time .canvas-ctt { min-height: 240px; }
    .wrapper-crm-tickets-time .body-ctt { min-height: 240px; }
  }
  @media (max-width: 480px) {
    .wrapper-crm-tickets-time .card-ctt { min-height: 300px; padding: 14px; }
    .wrapper-crm-tickets-time .head-ctt { margin-bottom: 10px; }
    .wrapper-crm-tickets-time .title-ctt { font-size: 13.5px; }
    .wrapper-crm-tickets-time .sub-ctt { font-size: 10.5px; }
    .wrapper-crm-tickets-time .canvas-ctt { min-height: 220px; }
    .wrapper-crm-tickets-time .body-ctt { min-height: 220px; }
  }
}
@media (prefers-reduced-motion: reduce) {
  .wrapper-crm-tickets-time .card-ctt { transition: none; }
}
